import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './OrderManagement.css';

const OrderManagement = () => {
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedOrder, setSelectedOrder] = useState(null);
    const [filter, setFilter] = useState('all');
    const [stats, setStats] = useState(null);

    useEffect(() => {
        fetchOrders();
        fetchStats();
    }, [filter]);

    const fetchOrders = async () => {
        setLoading(true);
        try {
            const res = await axios.get(`http://localhost:5000/api/admin/orders?status=${filter}`);
            setOrders(res.data.orders || []);
        } catch (error) {
            console.error('Lỗi tải đơn hàng:', error);
        } finally {
            setLoading(false);
        }
    };

    const fetchStats = async () => {
        try {
            const res = await axios.get('http://localhost:5000/api/admin/orders/stats/summary');
            setStats(res.data.stats);
        } catch (error) {
            console.error('Lỗi tải thống kê:', error);
        }
    };

    const updateOrderStatus = async (orderId, status) => {
        if (window.confirm(`Bạn có chắc muốn cập nhật trạng thái đơn hàng thành "${status}"?`)) {
            try {
                await axios.put(`http://localhost:5000/api/admin/orders/${orderId}/status`, { status });
                alert('Cập nhật trạng thái thành công!');
                fetchOrders();
                fetchStats();
            } catch (error) {
                alert('Lỗi: ' + (error.response?.data?.message || 'Cập nhật thất bại'));
            }
        }
    };

    const viewOrderDetail = async (orderId) => {
        try {
            const res = await axios.get(`http://localhost:5000/api/admin/orders/${orderId}`);
            setSelectedOrder(res.data.order);
        } catch (error) {
            console.error('Lỗi tải chi tiết:', error);
        }
    };

    // Sửa hàm formatPrice - thêm kiểm tra null/undefined
    const formatPrice = (price) => {
        if (!price && price !== 0) return '0 ₫';
        return price.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.') + ' ₫';
    };

    const formatDate = (dateString) => {
        if (!dateString) return 'Chưa có';
        return new Date(dateString).toLocaleString('vi-VN');
    };

    const getStatusBadge = (status) => {
        const badges = {
            pending: { text: '⏳ Chờ xác nhận', class: 'badge-pending' },
            confirmed: { text: '✅ Đã xác nhận', class: 'badge-confirmed' },
            shipping: { text: '🚚 Đang giao', class: 'badge-shipping' },
            completed: { text: '✔️ Hoàn thành', class: 'badge-completed' },
            cancelled: { text: '❌ Đã hủy', class: 'badge-cancelled' }
        };
        return badges[status] || badges.pending;
    };

    if (loading) return <div className="loading">Đang tải...</div>;

    return (
        <div className="order-management">
            <h1>📦 Quản lý đơn hàng</h1>

            {/* Thống kê */}
            {stats && (
                <div className="stats-grid">
                    <div className="stat-card">
                        <h3>Tổng đơn hàng</h3>
                        <div className="stat-number">{stats.total_orders || 0}</div>
                    </div>
                    <div className="stat-card pending">
                        <h3>Chờ xác nhận</h3>
                        <div className="stat-number">{stats.pending_orders || 0}</div>
                    </div>
                    <div className="stat-card confirmed">
                        <h3>Đã xác nhận</h3>
                        <div className="stat-number">{stats.confirmed_orders || 0}</div>
                    </div>
                    <div className="stat-card shipping">
                        <h3>Đang giao</h3>
                        <div className="stat-number">{stats.shipping_orders || 0}</div>
                    </div>
                    <div className="stat-card completed">
                        <h3>Hoàn thành</h3>
                        <div className="stat-number">{stats.completed_orders || 0}</div>
                    </div>
                    <div className="stat-card revenue">
                        <h3>Doanh thu</h3>
                        <div className="stat-number">{formatPrice(stats.total_revenue)}</div>
                    </div>
                </div>
            )}

            {/* Bộ lọc */}
            <div className="filter-bar">
                <select value={filter} onChange={(e) => setFilter(e.target.value)}>
                    <option value="all">📋 Tất cả đơn hàng</option>
                    <option value="pending">⏳ Chờ xác nhận</option>
                    <option value="confirmed">✅ Đã xác nhận</option>
                    <option value="shipping">🚚 Đang giao</option>
                    <option value="completed">✔️ Hoàn thành</option>
                    <option value="cancelled">❌ Đã hủy</option>
                </select>
            </div>

            {/* Bảng đơn hàng */}
            <table className="admin-table">
                <thead>
                    <tr>
                        <th>Mã đơn</th>
                        <th>Khách hàng</th>
                        <th>SĐT</th>
                        <th>Tổng tiền</th>
                        <th>Số lượng</th>
                        <th>Trạng thái</th>
                        <th>Ngày đặt</th>
                        <th>Thao tác</th>
                    </tr>
                </thead>
                <tbody>
                    {orders.length === 0 ? (
                        <tr>
                            <td colSpan="8" style={{ textAlign: 'center' }}>
                                Không có đơn hàng nào
                            </td>
                        </tr>
                    ) : (
                        orders.map(order => {
                            const status = getStatusBadge(order.status);
                            return (
                                <tr key={order.id}>
                                    <td><strong>{order.order_code}</strong></td>
                                    <td>
                                        {order.user_name}
                                        <br />
                                        <small>{order.user_email}</small>
                                    </td>
                                    <td>{order.shipping_phone || 'Chưa có'}</td>
                                    <td className="price">{formatPrice(order.total_amount)}</td>
                                    <td>{order.items_count || 0}</td>
                                    <td>
                                        <select
                                            value={order.status}
                                            onChange={(e) => updateOrderStatus(order.id, e.target.value)}
                                            className={`status-select ${order.status}`}
                                        >
                                            <option value="pending">⏳ Chờ xác nhận</option>
                                            <option value="confirmed">✅ Đã xác nhận</option>
                                            <option value="shipping">🚚 Đang giao</option>
                                            <option value="completed">✔️ Hoàn thành</option>
                                            <option value="cancelled">❌ Đã hủy</option>
                                        </select>
                                    </td>
                                    <td>{formatDate(order.created_at)}</td>
                                    <td>
                                        <button 
                                            onClick={() => viewOrderDetail(order.id)}
                                            className="btn-view"
                                        >
                                            Chi tiết
                                        </button>
                                    </td>
                                </tr>
                            );
                        })
                    )}
                </tbody>
            </table>

            {/* Modal chi tiết đơn hàng */}
            {selectedOrder && (
                <div className="modal" onClick={() => setSelectedOrder(null)}>
                    <div className="modal-content large" onClick={e => e.stopPropagation()}>
                        <span className="close" onClick={() => setSelectedOrder(null)}>&times;</span>
                        
                        <h2>Chi tiết đơn hàng</h2>
                        <p className="order-code">Mã đơn: <strong>{selectedOrder.order_code}</strong></p>
                        
                        {/* Thông tin khách hàng */}
                        <div className="info-section">
                            <h3>👤 Thông tin khách hàng</h3>
                            <div className="info-grid">
                                <div><label>Họ tên:</label> {selectedOrder.shipping_name || 'Chưa có'}</div>
                                <div><label>Email:</label> {selectedOrder.user_email || 'Chưa có'}</div>
                                <div><label>SĐT:</label> {selectedOrder.shipping_phone || 'Chưa có'}</div>
                                <div><label>Địa chỉ:</label> {selectedOrder.shipping_address || 'Chưa có'}</div>
                                {selectedOrder.note && (
                                    <div><label>Ghi chú:</label> {selectedOrder.note}</div>
                                )}
                            </div>
                        </div>

                        {/* Thông tin đơn hàng */}
                        <div className="info-section">
                            <h3>📦 Sản phẩm</h3>
                            <table className="order-items-table">
                                <thead>
                                    <tr>
                                        <th>Sản phẩm</th>
                                        <th>Đơn giá</th>
                                        <th>Số lượng</th>
                                        <th>Thành tiền</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {selectedOrder.items && selectedOrder.items.map(item => (
                                        <tr key={item.id}>
                                            <td>
                                                <div className="product-info">
                                                    {item.image_url && (
                                                        <img src={item.image_url} alt={item.car_name} />
                                                    )}
                                                    <span>{item.car_name}</span>
                                                </div>
                                            </td>
                                            <td>{formatPrice(item.price)}</td>
                                            <td>{item.quantity}</td>
                                            <td>{formatPrice(item.price * item.quantity)}</td>
                                        </tr>
                                    ))}
                                </tbody>
                                <tfoot>
                                    <tr>
                                        <td colSpan="3" className="text-right"><strong>Tổng cộng:</strong></td>
                                        <td className="total-price">{formatPrice(selectedOrder.total_amount)}</td>
                                    </tr>
                                    <tr>
                                        <td colSpan="3" className="text-right"><strong>Phí vận chuyển:</strong></td>
                                        <td>Miễn phí</td>
                                    </tr>
                                </tfoot>
                            </table>
                        </div>

                        {/* Thông tin thanh toán */}
                        <div className="info-section">
                            <h3>💳 Thông tin thanh toán</h3>
                            <div className="info-grid">
                                <div><label>Phương thức:</label> 
                                    {selectedOrder.payment_method === 'cod' ? '💰 Thanh toán khi nhận hàng' :
                                     selectedOrder.payment_method === 'banking' ? '🏦 Chuyển khoản ngân hàng' :
                                     '📱 Ví Momo'}
                                </div>
                                <div><label>Trạng thái:</label> 
                                    <span className={selectedOrder.payment_status === 'paid' ? 'paid' : 'unpaid'}>
                                        {selectedOrder.payment_status === 'paid' ? '✅ Đã thanh toán' : '⏳ Chưa thanh toán'}
                                    </span>
                                </div>
                                <div><label>Trạng thái đơn:</label> 
                                    <span className={`order-status ${selectedOrder.status}`}>
                                        {selectedOrder.status === 'pending' ? '⏳ Chờ xác nhận' :
                                         selectedOrder.status === 'confirmed' ? '✅ Đã xác nhận' :
                                         selectedOrder.status === 'shipping' ? '🚚 Đang giao' :
                                         selectedOrder.status === 'completed' ? '✔️ Hoàn thành' : '❌ Đã hủy'}
                                    </span>
                                </div>
                            </div>
                        </div>

                        <div className="modal-actions">
                            <select 
                                value={selectedOrder.status}
                                onChange={(e) => updateOrderStatus(selectedOrder.id, e.target.value)}
                                className="status-update"
                            >
                                <option value="pending">⏳ Chờ xác nhận</option>
                                <option value="confirmed">✅ Đã xác nhận</option>
                                <option value="shipping">🚚 Đang giao</option>
                                <option value="completed">✔️ Hoàn thành</option>
                                <option value="cancelled">❌ Đã hủy</option>
                            </select>
                            <button onClick={() => setSelectedOrder(null)} className="close-btn">
                                Đóng
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default OrderManagement;
